mapper.select:
SELECT p.PLC_NO AS plcNo, p.PLC_ID AS plcId, p.PLC_RGN_CD AS plcRgnCd, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_LAT AS plcLat, p.PLC_LOT AS plcLot, p.PLC_TELNO AS plcTelno, p.PLC_OVERVIEW AS plcOverview, p.PLC_MAIN_IMG_URL AS plcMainImgUrl, p.PLC_THUM_IMG_URL AS plcThumImgUrl, p.PLC_FLT_CD AS plcFltCd, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_REVIEW_CNT AS plcReviewCnt, s.SEE_USETIME AS seeUsetime, s.SEE_PARKING AS seeParking, s.SEE_RESTDATE AS seeRestdate, s.SEE_INFOCENTER AS seeInfocenter FROM PLACE p LEFT JOIN PLACE_SEE s ON p.PLC_NO = s.SEE_PLC_NO WHERE p.PLC_CAT_CD = 'PLC001'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC
